import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as n,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/magnet-transfer.md","filePath":"th-TH/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"th-TH/Other/magnet-transfer.md"};function p(h,a,c,m,u,g){return n(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer ดาวน์โหลด files จาก magnet link แล้ว upload อัตโนมัติไปยัง cloud storage channel ที่คุณเลือก</p><p>เหมาะกับการย้าย anime episodes, videos, archives และ files ลักษณะใกล้เคียง Paste magnet link แล้ว ImgBed จะสร้าง background download task เมื่อ download เสร็จ file จะถูก upload เข้า ImgBed และ final link จะแสดงใน upload list</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="ใช้จากที่ไหน" tabindex="-1">ใช้จากที่ไหน <a class="header-anchor" href="#ใช้จากที่ไหน" aria-label="Permalink to &quot;ใช้จากที่ไหน&quot;">​</a></h2><p>Magnet transfer entry อยู่ใน homepage upload area</p><p>Paste magnet link ลงใน input box เลือก <code>Transfer</code> แล้ว upload</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="ก่อนใช้งานครั้งแรก" tabindex="-1">ก่อนใช้งานครั้งแรก <a class="header-anchor" href="#ก่อนใช้งานครั้งแรก" aria-label="Permalink to &quot;ก่อนใช้งานครั้งแรก&quot;">​</a></h2><p>ต้อง configure magnet transfer ใน admin panel ก่อน</p><p>โดยทั่วไปต้องมี:</p><ol><li>GitHub account สำหรับ run download task</li><li>Cloud upload channel เช่น Google Drive หรือ OneDrive</li><li>Target upload directory</li><li>Task timeout</li></ol><p>เมื่อตั้งค่าพร้อมแล้ว กลับไปหน้า homepage และ paste magnet link เพื่อเริ่ม transfer</p><h2 id="upload-magnet-link" tabindex="-1">Upload Magnet Link <a class="header-anchor" href="#upload-magnet-link" aria-label="Permalink to &quot;Upload Magnet Link&quot;">​</a></h2><ol><li>Paste magnet link ใน homepage upload box</li><li>ตรวจว่า mode ตั้งเป็น <code>Transfer</code></li><li>คลิก upload</li><li>รอ ImgBed create magnet task</li><li>หลัง task เริ่ม ให้ใช้ floating panel <code>Magnet Tasks</code> มุมขวาล่างเพื่อตรวจ progress</li></ol><p>Download และ upload อาจใช้เวลา Speed ขึ้นกับ magnet resource, GitHub runtime environment และ selected cloud storage channel</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="หลัง-completion" tabindex="-1">หลัง Completion <a class="header-anchor" href="#หลัง-completion" aria-label="Permalink to &quot;หลัง Completion&quot;">​</a></h2><p>เมื่อ task complete upload list จะแสดง file name และ link</p><p>Videos แสดง video preview, images แสดง image preview และ other files แสดง regular file icon</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>Copy ได้:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>Direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts หรือ notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>Forums ที่รองรับ BBCode</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>Magnet task panel มุมขวาล่างแสดง task count, task name, progress และ final status</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>Task ถูกสร้างแล้วและรอ run</td></tr><tr><td>Downloading</td><td>Magnet resource กำลัง download</td></tr><tr><td>Uploading</td><td>File download เสร็จแล้วและกำลัง upload เข้า cloud storage</td></tr><tr><td>Completed</td><td>Upload สำเร็จและ copy link ได้</td></tr><tr><td>Failed</td><td>Task ไม่เสร็จสมบูรณ์ ตรวจ message แล้วลองใหม่</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>ถ้า magnet link มีหลาย files ImgBed จะ prioritize main completed file สำหรับ display</li><li>Large files ใช้เวลานาน รอ task finish ก่อน refresh page</li><li>ถ้า magnet resource ไม่มี available peers อาจช้ามากหรือ fail</li><li>ถ้า cloud account quota เต็ม, authorization หมดอายุ หรือ upload directory ผิด task อาจ fail</li><li>Video preview อาจใช้เวลาสักครู่หลัง upload complete</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="paste-magnet-link-แล้วไม่มีอะไรเริ่ม" tabindex="-1">Paste Magnet Link แล้วไม่มีอะไรเริ่ม <a class="header-anchor" href="#paste-magnet-link-แล้วไม่มีอะไรเริ่ม" aria-label="Permalink to &quot;Paste Magnet Link แล้วไม่มีอะไรเริ่ม&quot;">​</a></h3><p>Confirm ว่า magnet transfer enabled ใน admin panel และเลือก GitHub account กับ cloud channel ที่ใช้งานได้แล้ว</p><h3 id="download-ช้าตลอด" tabindex="-1">Download ช้าตลอด <a class="header-anchor" href="#download-ช้าตลอด" aria-label="Permalink to &quot;Download ช้าตลอด&quot;">​</a></h3><p>Magnet speed ขึ้นกับ resource เอง ถ้าไม่มี available peers download อาจช้ามากหรือเป็นไปไม่ได้</p><h3 id="upload-แล้วไม่เห็น-preview" tabindex="-1">Upload แล้วไม่เห็น Preview <a class="header-anchor" href="#upload-แล้วไม่เห็น-preview" aria-label="Permalink to &quot;Upload แล้วไม่เห็น Preview&quot;">​</a></h3><p>ก่อนอื่น confirm ว่า file link เปิดได้ Video files อาจต้องใช้เวลาสั้น ๆ เพื่อ load ใน browser หรือเปิด link โดยตรงได้</p><h3 id="task-fail-ควรตรวจอะไร" tabindex="-1">Task fail ควรตรวจอะไร? <a class="header-anchor" href="#task-fail-ควรตรวจอะไร" aria-label="Permalink to &quot;Task fail ควรตรวจอะไร?&quot;">​</a></h3><p>ตรวจว่า magnet link valid, cloud channel ทำงานได้ และ upload directory ถูกต้อง จากนั้น submit task ใหม่</p>',38)])])}const _=i(s,[["render",p]]);export{b as __pageData,_ as default};
